// A deterministic daily time series (no randomness, so the demo is stable).
// Enough points that a pinch/pan actually has somewhere to go.
function momentumSeries() {
  var out = []
  var start = new Date('2023-01-01').getTime()
  var day = 86400000
  var v = 120
  for (var i = 0; i < 220; i++) {
    // smooth composite drift: a couple of sines plus a slow trend
    v = 120 + 38 * Math.sin(i / 13) + 18 * Math.sin(i / 4.5) + i * 0.32
    out.push([start + i * day, Math.round(v * 100) / 100])
  }
  return out
}

var options = {
  series: [{ name: 'Reading', data: momentumSeries() }],
  chart: {
    id: 'momentumChart',
    height: 400,
    type: 'area',
    fontFamily: 'Helvetica, Arial, sans-serif',
    animations: { enabled: false },
    toolbar: {
      autoSelected: 'pan',
      tools: {
        pan: true,
        zoom: true,
        zoomin: true,
        zoomout: true,
        reset: true,
        download: false,
      },
    },
    zoom: {
      enabled: true,
      type: 'x',
      pinch: true,
    },
    pan: {
      inertia: true,
      friction: 0.92,
    },
  },
  colors: ['#4f46e5'],
  dataLabels: { enabled: false },
  stroke: { curve: 'smooth', width: 2 },
  fill: {
    type: 'gradient',
    gradient: {
      shadeIntensity: 0.3,
      opacityFrom: 0.35,
      opacityTo: 0.03,
      stops: [0, 100],
    },
  },
  title: { text: 'Sensor reading (220 days)', align: 'left' },
  subtitle: {
    text: 'Pinch to zoom, two-finger pan, flick to glide',
    align: 'left',
  },
  xaxis: {
    type: 'datetime',
  },
  yaxis: {
    labels: {
      formatter: function (v) {
        return Math.round(v)
      },
    },
  },
  tooltip: { x: { format: 'dd MMM yyyy' } },
}

var chart = new ApexCharts(document.querySelector('#chart'), options)
chart.render()

var gestureEl = document.getElementById('gesture')
var windowEl = document.getElementById('window')

function fmt(ts) {
  var d = new Date(ts)
  return d.toISOString().slice(0, 10)
}
function showWindow(label, xaxis) {
  gestureEl.innerHTML = label
  if (xaxis && xaxis.min != null && xaxis.max != null) {
    windowEl.innerHTML = fmt(xaxis.min) + '  to  ' + fmt(xaxis.max)
  }
}

// zoomed fires at the end of a pinch (and on wheel / toolbar zoom); scrolled
// fires continuously while panning and once the inertia glide comes to rest.
chart.addEventListener('zoomed', function (c, opts) {
  showWindow('zoomed', opts.xaxis)
})
chart.addEventListener('scrolled', function (c, opts) {
  showWindow('panned', opts.xaxis)
})

#chart {
  max-width: 820px;
  margin: 16px auto;
}
.panel {
  max-width: 820px;
  margin: 16px auto;
  font-family: sans-serif;
}
.readout {
  display: flex;
  gap: 18px;
  align-items: center;
  flex-wrap: wrap;
  font-size: 13px;
  color: #334;
  margin-bottom: 6px;
}
.readout b {
  font-family: monospace;
}
.pill {
  background: #eef2ff;
  color: #4338ca;
  border-radius: 999px;
  padding: 3px 11px;
  font-weight: 600;
}
.note {
  background: #f5f8ff;
  border-left: 3px solid #4f46e5;
  padding: 11px 15px;
  font-size: 13px;
  color: #234;
  border-radius: 2px;
  line-height: 1.6;
}
.note code {
  background: #e6ecff;
  padding: 1px 5px;
  border-radius: 3px;
}
.gestures {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(210px, 1fr));
  gap: 10px;
  margin: 4px 0 2px;
}
.gesture {
  border: 1px solid #e2e6f0;
  border-radius: 8px;
  padding: 10px 13px;
  font-family: sans-serif;
}
.gesture h4 {
  margin: 0 0 3px;
  font-size: 13px;
  color: #4338ca;
}
.gesture p {
  margin: 0;
  font-size: 12.5px;
  color: #445;
  line-height: 1.5;
}
